from dataclasses import dataclass, field
from datetime import date, timedelta
from typing import List, Optional, Dict
from enum import Enum

class CertTier(Enum):
    PRACTITIONER = "practitioner"
    ADVANCED = "practitioner_advanced"
    CHAMPION = "champion"

class AssessmentResult(Enum):
    PASS = "pass"
    CONDITIONAL_PASS = "conditional_pass"
    FAIL = "fail"
    NOT_ATTEMPTED = "not_attempted"

@dataclass
class LabSession:
    session_id: str
    employee_id: str
    role_family: str
    exercises_completed: List[str]
    duration_minutes: int
    facilitator: Optional[str]
    score_pct: Optional[float] = None
    notes: str = ""

@dataclass
class Certification:
    cert_id: str
    employee_id: str
    employee_name: str
    role_family: str
    tier: CertTier
    issued_date: date
    validity_months: int = 24

    @property
    def expiry_date(self) -> date:
        return self.issued_date + timedelta(days=self.validity_months * 30)

    @property
    def is_valid(self) -> bool:
        return date.today() <= self.expiry_date

    @property
    def days_to_expiry(self) -> int:
        return (self.expiry_date - date.today()).days

    def renewal_alert(self) -> Optional[str]:
        if self.days_to_expiry < 0:
            return f"EXPIRED {abs(self.days_to_expiry)} days ago"
        if self.days_to_expiry <= 90:
            return f"Expires in {self.days_to_expiry} days — renewal required"
        return None

@dataclass
class CertificationRegistry:
    certs: List[Certification] = field(default_factory=list)

    def add(self, cert: Certification) -> None:
        self.certs.append(cert)

    def expiring_soon(self, days: int = 90) -> List[Certification]:
        return [c for c in self.certs if 0 <= c.days_to_expiry <= days]

    def expired(self) -> List[Certification]:
        return [c for c in self.certs if not c.is_valid]

    def by_tier(self) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for c in self.certs:
            if c.is_valid:
                counts[c.tier.value] = counts.get(c.tier.value, 0) + 1
        return counts

    def status_report(self) -> str:
        lines = [
            f"Certification Registry: {len(self.certs)} total",
            f"By tier (valid only): {self.by_tier()}",
            f"Expiring in 90 days: {len(self.expiring_soon())}",
            f"Expired: {len(self.expired())}",
        ]
        for c in self.expiring_soon():
            alert = c.renewal_alert()
            if alert:
                lines.append(f"  - {c.employee_name} ({c.tier.value}): {alert}")
        return "\n".join(lines)

registry = CertificationRegistry()
registry.add(Certification("C001", "E100", "Alice B.", "Customer Success", CertTier.PRACTITIONER, date(2024, 6, 1)))
registry.add(Certification("C002", "E101", "Bob K.", "Customer Success", CertTier.ADVANCED, date(2025, 5, 1)))
registry.add(Certification("C003", "E102", "Carol S.", "Legal Review", CertTier.PRACTITIONER, date(2025, 6, 15)))

print(registry.status_report())
